 1	import React, { FC, memo } from 'react';
 2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { useWizardVMContext } from '@catalog/utils/WizardVMContext';
 5	import SidebarEditorSwitch from '@kubevirt-utils/components/SidebarEditor/SidebarEditorSwitch';
 6	import { DEFAULT_NAMESPACE } from '@kubevirt-utils/constants/constants';
 7	import { VirtualMachineDetailsTab } from '@kubevirt-utils/constants/tabs-constants';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import {
10	  Breadcrumb,
11	  BreadcrumbItem,
12	  Button,
13	  Split,
14	  Text,
15	  TextVariants,
16	  Title,
17	} from '@patternfly/react-core';
18	
19	export const WizardHeader: FC<{ namespace: string }> = memo(({ namespace }) => {
20	  const { t } = useKubevirtTranslation();
21	  const { tabsData } = useWizardVMContext();
22	  const navigate = useNavigate();
23	  const location = useLocation();
24	
25	  const templateName = tabsData?.overview?.templateMetadata?.name;
26	  const templateDisplayName = tabsData?.overview?.templateMetadata?.displayName || templateName;
27	
28	  const onBreadcrumbClick = (url: string) =>
29	    confirm(t('Are you sure you want to leave this page?')) && navigate(url);
30	
31	  const isSidebarEditorDisplayed = !location.pathname.includes(
32	    `/catalog/template/review/${VirtualMachineDetailsTab.YAML}`,
33	  );
34	
35	  return (
36	    <div className="pf-v6-c-page__main-breadcrumb wizard-header">
37	      <Breadcrumb className="pf-v6-c-breadcrumb co-breadcrumb">
38	        <BreadcrumbItem>
39	          <Button
40	            onClick={() =>
41	              onBreadcrumbClick(`/k8s/ns/${namespace || DEFAULT_NAMESPACE}/catalog/template`)
42	            }
43	            isInline
44	            variant="link"
45	          >
46	            {t('Catalog')}
47	          </Button>
48	        </BreadcrumbItem>
49	      </Breadcrumb>
50	      <Split hasGutter>
51	        <Title headingLevel="h1">{t('Customize and create VirtualMachine')}</Title>
52	        {isSidebarEditorDisplayed && <SidebarEditorSwitch />}
53	      </Split>
54	      <Text component={TextVariants.small} data-test="wizard title help">
55	        {t('Template: {{templateDisplayName}}', { templateDisplayName })}
56	      </Text>
57	    </div>
58	  );
59	});
60	WizardHeader.displayName = 'WizardHeader';

